const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs').promises;
const { exec } = require('child_process');
const util = require('util');
const sharp = require('sharp');

const app = express();
const execPromise = util.promisify(exec);

// Ensure upload directory exists
const uploadDir = path.join(__dirname, 'public', 'uploads');
fs.mkdir(uploadDir, { recursive: true });

// File type validation
const allowedTypes = {
  image: ['image/jpeg', 'image/png', 'image/gif', 'image/svg+xml'],
  document: ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'],
  archive: ['application/zip', 'application/x-zip-compressed']
};

const fileFilter = (req, file, cb) => {
  const isAllowed = Object.values(allowedTypes).some(typeGroup => 
    typeGroup.includes(file.mimetype)
  );
  
  if (isAllowed) {
    cb(null, true);
  } else {
    cb(new Error('Invalid file type'), false);
  }
};

// Multer configuration
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, uploadDir);
  },
  filename: (req, file, cb) => {
    const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
    const ext = path.extname(file.originalname);
    cb(null, file.fieldname + '-' + uniqueSuffix + ext);
  }
});

const upload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: {
    fileSize: 100 * 1024 * 1024 // 100MB limit for non-enterprise
  }
});

// Enterprise user check (mock implementation)
const isEnterpriseUser = (req) => {
  // Implement your enterprise user detection logic here
  return false;
};

// Generate thumbnail for images
const generateThumbnail = async (filePath, fileName) => {
  try {
    const thumbnailPath = path.join(uploadDir, 'thumb_' + fileName);
    await sharp(filePath)
      .resize(200, 200, { fit: 'cover' })
      .toFile(thumbnailPath);
  } catch (error) {
    console.error('Thumbnail generation failed:', error);
  }
};

// Process uploaded files
const processFile = async (req, res, next) => {
  try {
    if (!req.file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    const file = req.file;
    
    // Check if it's an image and generate thumbnail
    if (allowedTypes.image.includes(file.mimetype)) {
      await generateThumbnail(file.path, file.filename);
    }

    // Check if it's an archive and perform safety checks
    if (allowedTypes.archive.includes(file.mimetype)) {
      // Perform archive safety checks
      await execPromise(`unzip -l "${file.path}"`);
    }

    res.json({
      message: 'File uploaded successfully',
      filename: file.filename,
      originalname: file.originalname,
      size: file.size,
      mimetype: file.mimetype
    });
  } catch (error) {
    console.error('File processing error:', error);
    res.status(500).json({ error: 'File processing failed' });
  }
};

// Upload endpoint
app.post('/upload', (req, res, next) => {
  // Apply size limits based on user type
  if (isEnterpriseUser(req)) {
    // No size limit for enterprise users
    upload.single('file')(req, res, next);
  } else {
    // Apply size limit for regular users
    const uploadLimited = multer({
      storage: storage,
      fileFilter: fileFilter,
      limits: {
        fileSize: 10 * 1024 * 1024 // 10MB limit for regular users
      }
    });
    uploadLimited.single('file')(req, res, next);
  }
}, processFile);

